    38→export function groupClaudeTurns(items: DisplayItem[]): RenderItem[] {
    39→  const result: RenderItem[] = [];
    40→  let i = 0;
    41→  while (i < items.length) {
    42→    const item = items[i];
    43→    if (item.kind === "toolGroup") {
    44→      const toolGroups: ToolUseData[][] = [];
    45→      while (i < items.length && items[i].kind === "toolGroup") {
    46→        toolGroups.push((items[i] as { kind: "toolGroup"; tools: ToolUseData[] }).tools);
    47→        i++;
    48→      }
    49→      let stop: Event | null = null;
    50→      if (i < items.length && items[i].kind === "event" && (items[i] as { kind: "event"; event: Event }).event.event === "Stop") {
    51→        stop = (items[i] as { kind: "event"; event: Event }).event;
    52→        i++;
    53→      }
    54→      result.push({ kind: "claudeTurn", toolGroups, stop });
    55→    } else if (item.kind === "event" && item.event.event === "Stop") {
    56→      result.push({ kind: "claudeTurn", toolGroups: [], stop: item.event });
    57→      i++;
    58→    } else if (item.kind === "checkpoint") {
    59→      result.push({ kind: "checkpoint", checkpoint: item.checkpoint });
    60→      i++;
    61→    } else {
    62→      result.push({ kind: "event", event: (item as { kind: "event"; event: Event }).event });
    63→      i++;
    64→    }
    65→  }
    66→  return result;
    67→}
