    92→  expandThinking?: boolean;
    93→  targetLogEventId?: number | null;
    94→}) {
    95→  const d = stop ? (stop.data ?? {}) as Record<string, unknown> : {};
    96→  const msg = str(d.last_assistant_message);
    97→  const thinking = str(d.thinking);
    98→  const reason = str(d.reason);
    99→  const thinkingLogEventId = typeof d.thinkingLogEventId === "number" ? d.thinkingLogEventId : null;
   100→  const thinkingUuid = typeof d.thinkingUuid === "string" ? d.thinkingUuid : null;
   101→  const toolsLogEventId = typeof d.toolsLogEventId === "number" ? d.toolsLogEventId : null;
   102→  const toolsUuid = typeof d.toolsUuid === "string" ? d.toolsUuid : null;
   103→  const [toolsExpanded, setToolsExpanded] = useState(false);
   104→  const [thinkingExpanded, setThinkingExpanded] = useState(false);
   105→  const totalTools = toolGroups.reduce((n, g) => n + g.length, 0);
   106→
   107→  useEffect(() => {
   108→    if (expandThinking && thinking) setThinkingExpanded(true);
   109→  }, [expandThinking, thinking]);
   110→
   111→  useEffect(() => {
   112→    if (expandTools && totalTools > 0) setToolsExpanded(true);
   113→  }, [expandTools, totalTools]);
   114→
   115→  return (
   116→    <Box style={{ display: "flex", padding: "12px 20px 4px", gap: 10 }}>
   117→      <img src={claudeLogo} alt="Claude" style={{ width: 28, height: 28, borderRadius: "50%", flexShrink: 0, marginTop: 2 }} />
   118→      <Box style={{ flex: 1, minWidth: 0 }}>
   119→        <Group gap={8} mb={6} align="center">
   120→          <Text size="xs" fw={600} c="orange">Claude</Text>
   121→          {reason && <Badge color="orange" size="xs" variant="light">{reason}</Badge>}
   122→          {stop && <TimeAgo iso={stop.timestamp} />}
   123→        </Group>
   124→        {thinking && (
   125→          <Box mb={6} id={thinkingUuid ?? (thinkingLogEventId != null ? `log-event-${thinkingLogEventId}` : undefined)}>
   126→            <Group
   127→              gap={6}
   128→              mb={4}
   129→              style={{ cursor: "pointer" }}
   130→              onClick={() => setThinkingExpanded((v) => !v)}
   131→            >
   132→              <Text size="xs" c="dimmed" fs="italic">thinking {thinkingExpanded ? "▲" : "▼"}</Text>
   133→            </Group>
   134→            <Collapse in={thinkingExpanded}>
   135→              <Box style={{
   136→                backgroundColor: "light-dark(var(--mantine-color-gray-0), var(--mantine-color-dark-7))",
   137→                border: "1px solid light-dark(var(--mantine-color-gray-2), var(--mantine-color-dark-5))",
   138→                borderRadius: 8,
