   190→// TODO: we're dropping the UUIDs from LogEventItems, or at least mixing them up into currentTurnLogEventIds.
   191→// We need to attach these UUIDs to the components that these generate. That way the scrolling will work.
   192→/**
   193→ * Convert LogEventItems (from full.jsonl tables) into pseudo-Event objects that
   194→ * match the shape the existing UI components expect.  This lets all downstream
   195→ * grouping and rendering code remain unchanged.
   196→ */
   197→export function logEventsToEvents(logEvents: LogEventItem[]): Event[] {
   198→  const result: Event[] = [];
   199→  let id = -1;
   200→  let lastAssistantText: string | null = null;
   201→  let lastAssistantThinking: string | null = null;
   202→  let lastAssistantLogEventId: number | null = null;
   203→  let lastThinkingLogEventId: number | null = null;
   204→  let lastThinkingUuid: string | null = null;
   205→  let lastToolsLogEventId: number | null = null;
   206→  let lastToolsUuid: string | null = null;
   207→  // All LogEvent IDs seen in the current assistant turn (thinking, text, tool_use may be separate events)
   208→  const currentTurnLogEventIds: number[] = [];
   209→
   210→  // TODO: look at which event types are useful.
   211→  const filtered = logEvents.filter(
   212→    (e) => !e.isSidechain && e.type !== "file-history-snapshot" && e.type !== "progress",
   213→  );
   214→
   215→  // Virtual SessionStart divider
   216→  const first = filtered[0];
   217→  if (first) {
   218→    result.push({ id: id--, timestamp: first.timestamp ?? "", event: "SessionStart", sessionId: first.sessionId ?? "", blocked: false, data: { cwd: first.cwd ?? "" }, summary: null, keywords: [], _sourceLogEventId: first.id });
   219→  }
   220→
   221→  for (const le of filtered) {
   222→    const ts  = le.timestamp ?? "";
   223→    const sid = le.sessionId ?? "";
   224→
   225→    if (le.type === "user") {
   226→      const toolResults = le.contents.filter((c) => c.contentType === "tool_result");
   227→      // TODO: show images and other content types
   228→      const textBlocks  = le.contents.filter((c) => c.contentType === "text");
   229→
   230→      if (toolResults.length > 0) {
   231→        for (const tr of toolResults) {
   232→          const failed = tr.isError === true;
   233→          result.push({
   234→            id: id--,
   235→            timestamp: ts,
   236→            event: failed ? "PostToolUseFailure" : "PostToolUse",
   237→            sessionId: sid,
   238→            blocked: false,
   239→            data: {
   240→              tool_use_id:   tr.toolUseId,
   241→              tool_response: !failed ? (tr.toolResultContent ?? "") : undefined,
   242→              error:          failed ? (tr.toolResultContent ?? "") : undefined,
   243→            },
   244→            summary: null, keywords: [], _sourceLogEventId: le.id, _sourceUuid: le.uuid ?? undefined,
   245→          });
   246→        }
   247→      } else if (textBlocks.length > 0) {
   248→        const prompt = textBlocks.map((b) => b.text ?? "").join("\n\n");
   249→        result.push({ id: id--, timestamp: ts, event: "UserPromptSubmit", sessionId: sid, blocked: false, data: { prompt }, summary: null, keywords: [], _sourceLogEventId: le.id, _sourceUuid: le.uuid ?? undefined });
   250→      }
   251→
   252→    } else if (le.type === "assistant") {
   253→      const toolUses      = le.contents.filter((c) => c.contentType === "tool_use");
   254→      const textBlocks    = le.contents.filter((c) => c.contentType === "text");
   255→      const thinkingBlocks = le.contents.filter((c) => c.contentType === "thinking");
   256→
   257→      // Track all LogEvent IDs in this turn so thinking-only events are reachable
   258→      if (!currentTurnLogEventIds.includes(le.id)) currentTurnLogEventIds.push(le.id);
   259→
   260→      if (textBlocks.length > 0) {
   261→        const newText = textBlocks.map((b) => b.text ?? "").filter(Boolean).join("\n\n");
   262→        // If there was already planning text and tool uses have been emitted since,
   263→        // fold the planning text into the thinking block so it isn't lost.
   264→        if (lastAssistantText !== null && lastToolsLogEventId !== null) {
   265→          lastAssistantThinking = lastAssistantThinking
   266→            ? lastAssistantThinking + "\n\n" + lastAssistantText
   267→            : lastAssistantText;
   268→        }
   269→        lastAssistantText = newText;
   270→        lastAssistantLogEventId = le.id;
   271→      }
   272→      if (thinkingBlocks.length > 0) {
   273→        const thinking = thinkingBlocks.map((b) => b.thinking ?? "").filter(Boolean).join("\n\n");
   274→        lastAssistantThinking = lastAssistantThinking ? lastAssistantThinking + "\n\n" + thinking : thinking;
   275→        lastThinkingLogEventId = le.id;
   276→        lastThinkingUuid = le.uuid ?? null;
   277→        if (lastAssistantLogEventId === null) lastAssistantLogEventId = le.id;
   278→      }
   279→
   280→      for (const tu of toolUses) {
   281→        lastToolsLogEventId = le.id;
   282→        lastToolsUuid = le.uuid ?? null;
   283→        result.push({
   284→          id: id--,
   285→          timestamp: ts,
   286→          event: "PreToolUse",
   287→          sessionId: sid,
   288→          blocked: false,
   289→          data: { tool_name: tu.toolName ?? "?", tool_use_id: tu.toolUseId, tool_input: tu.toolInput },
   290→          summary: null, keywords: [], _sourceLogEventId: le.id, _sourceUuid: le.uuid ?? undefined,
   291→        });
   292→      }
   293→
   294→    } else if (le.type === "system" && le.systemData?.subtype === "stop_hook_summary") {
   295→      const primaryId = lastAssistantLogEventId ?? le.id;
   296→      const extraIds = currentTurnLogEventIds.filter((x) => x !== primaryId);
   297→      result.push({
   298→        id: id--,
   299→        timestamp: ts,
   300→        event: "Stop",
   301→        sessionId: sid,
   302→        blocked: le.systemData.preventedContinuation ?? false,
   303→        data: {
   304→          last_assistant_message: lastAssistantText ?? "",
   305→          thinking: lastAssistantThinking ?? "",
   306→          reason: le.systemData.stopReason ?? "",
   307→          thinkingLogEventId: lastThinkingLogEventId ?? undefined,
   308→          thinkingUuid: lastThinkingUuid ?? undefined,
   309→          toolsLogEventId: lastToolsLogEventId ?? undefined,
   310→          toolsUuid: lastToolsUuid ?? undefined,
   311→        },
   312→        summary: null, keywords: [],
   313→        _sourceLogEventId: primaryId,
   314→        _extraSourceLogEventIds: extraIds.length > 0 ? extraIds : undefined,
   315→      });
   316→      lastAssistantText = null;
   317→      lastAssistantThinking = null;
   318→      lastAssistantLogEventId = null;
   319→      lastThinkingLogEventId = null;
   320→      lastThinkingUuid = null;
   321→      lastToolsLogEventId = null;
   322→      lastToolsUuid = null;
   323→      currentTurnLogEventIds.length = 0;
   324→    }
   325→  }
   326→
   327→  // Flush any trailing assistant text that had no stop event
   328→  if (lastAssistantText !== null && filtered.length > 0) {
   329→    const last = filtered[filtered.length - 1];
   330→    const primaryId = lastAssistantLogEventId ?? last.id;
   331→    const extraIds = currentTurnLogEventIds.filter((x) => x !== primaryId);
   332→    result.push({
   333→      id: id--,
   334→      timestamp: last.timestamp ?? "",
   335→      event: "Stop",
   336→      sessionId: last.sessionId ?? "",
   337→      blocked: false,
   338→      data: { last_assistant_message: lastAssistantText, thinking: lastAssistantThinking ?? "", reason: "" },
   339→      summary: null, keywords: [],
   340→      _sourceLogEventId: primaryId,
   341→      _extraSourceLogEventIds: extraIds.length > 0 ? extraIds : undefined,
   342→    });
   343→  }
   344→
   345→  return result;
   346→}
