   348→export function groupEvents(events: Event[]): DisplayItem[] {
   349→  const postMap = new Map<string, Event>();
   350→  for (const event of events) {
   351→    if (event.event === "PostToolUse" || event.event === "PostToolUseFailure") {
   352→      const d = event.data as Record<string, unknown>;
   353→      const id = typeof d.tool_use_id === "string" ? d.tool_use_id : null;
   354→      if (id) postMap.set(id, event);
   355→    }
   356→  }
   357→
   358→  type RawItem =
   359→    | { kind: "event"; event: Event }
   360→    | { kind: "toolUse"; pre: Event; post?: Event; failed: boolean };
   361→
   362→  const raw: RawItem[] = [];
   363→  const consumed = new Set<number>();
   364→
   365→  for (const event of events) {
   366→    if ((event.event === "PostToolUse" || event.event === "PostToolUseFailure") && consumed.has(event.id)) continue;
   367→    if (event.event === "PreToolUse") {
   368→      const d = event.data as Record<string, unknown>;
   369→      const toolUseId = typeof d.tool_use_id === "string" ? d.tool_use_id : null;
   370→      const post = toolUseId ? postMap.get(toolUseId) : undefined;
   371→      if (post) consumed.add(post.id);
   372→      raw.push({ kind: "toolUse", pre: event, post, failed: post?.event === "PostToolUseFailure" });
   373→      continue;
   374→    }
   375→    raw.push({ kind: "event", event });
   376→  }
   377→
   378→  const isGroupable = (item: RawItem) =>
   379→    item.kind === "toolUse" || (item.kind === "event" && item.event.event === "Notification");
   380→
   381→  const result: DisplayItem[] = [];
   382→  let i = 0;
   383→  while (i < raw.length) {
   384→    if (isGroupable(raw[i])) {
   385→      const group: ToolUseData[] = [];
   386→      while (i < raw.length && isGroupable(raw[i])) {
   387→        const item = raw[i];
   388→        if (item.kind === "toolUse") group.push({ pre: item.pre, post: item.post, failed: item.failed });
   389→        i++;
   390→      }
   391→      if (group.length > 0) result.push({ kind: "toolGroup", tools: group });
   392→    } else {
   393→      result.push({ kind: "event", event: (raw[i] as { kind: "event"; event: Event }).event });
   394→      i++;
   395→    }
   396→  }
   397→  return result;
   398→}
