   560→// ── Search snippet helpers ─────────────────────────────────────────────────────
   561→
   562→function extractMatchTerms(snippet: string): string[] {
   563→  const terms: string[] = [];
   564→  const re = /«([^»]+)»/g;
   565→  let m: RegExpExecArray | null;
   566→  while ((m = re.exec(snippet)) !== null) terms.push(m[1]);
   567→  return [...new Set(terms)];
   568→}
   569→
   570→// ── Source log event ID extractor ─────────────────────────────────────────────
   571→
   572→function getItemSourceIds(item: RenderItem): number[] {
   573→  if (item.kind === "event") {
   574→    const ids = item.event._sourceLogEventId != null ? [item.event._sourceLogEventId] : [];
   575→    if (item.event._extraSourceLogEventIds) ids.push(...item.event._extraSourceLogEventIds);
   576→    return ids;
   577→  }
   578→  if (item.kind === "claudeTurn") {
   579→    const ids: number[] = [];
   580→    for (const group of item.toolGroups) {
   581→      for (const tool of group) {
   582→        if (tool.pre._sourceLogEventId != null) ids.push(tool.pre._sourceLogEventId);
   583→        if (tool.pre._extraSourceLogEventIds) ids.push(...tool.pre._extraSourceLogEventIds);
   584→        if (tool.post?._sourceLogEventId != null) ids.push(tool.post._sourceLogEventId);
   585→        if (tool.post?._extraSourceLogEventIds) ids.push(...tool.post._extraSourceLogEventIds);
   586→      }
   587→    }
   588→    if (item.stop?._sourceLogEventId != null) ids.push(item.stop._sourceLogEventId);
   589→    if (item.stop?._extraSourceLogEventIds) ids.push(...item.stop._extraSourceLogEventIds);
   590→    return ids;
   591→  }
   592→  return [];
   593→}
