   601→  const searchSnippet = (location.state as { snippet?: string; contentType?: string } | null)?.snippet ?? null;
   602→  const searchContentType = (location.state as { snippet?: string; contentType?: string } | null)?.contentType ?? null;
   603→  const [highlightActive, setHighlightActive] = useState(false);
   604→  const scrolledRef = useRef(false);
   605→  const viewportRef = useRef<HTMLDivElement>(null);
   606→  const logEventsRef = useRef<LogEventItem[]>([]);
   607→  const [session, setSession] = useState<Session | null>(null);
   608→  const [latestCheckpoint, setLatestCheckpoint] = useState<SessionCheckpoint | null>(null);
   609→  const [items, setItems] = useState<RenderItem[]>([]);
   610→  const [userInfo, setUserInfo] = useState<UserInfo | undefined>(undefined);
   611→  const [openItems, setOpenItems] = useState<OpenItem[]>([]);
   612→  const [selectedItems, setSelectedItems] = useState<Set<number>>(new Set());
   613→  const [spawning, setSpawning] = useState(false);
