     9→// ── Snippet renderer ──────────────────────────────────────────────────────────
    10→
    11→/** Highlight matched terms inside a plain-text string (for code/pre blocks). */
    12→function HighlightedCode({ raw }: { raw: string }) {
    13→  const parts = raw.split(/(«[^»]*»)/g);
    14→  return (
    15→    <code
    16→      style={{
    17→        display: "block",
    18→        whiteSpace: "pre-wrap",
    19→        wordBreak: "break-all",
    20→        fontFamily: "monospace",
    21→        fontSize: 12,
    22→        lineHeight: 1.5,
    23→        color: "inherit",
    24→      }}
    25→    >
    26→      {parts.map((part, i) => {
    27→        if (part.startsWith("«") && part.endsWith("»")) {
    28→          return (
    29→            <mark
    30→              key={i}
    31→              style={{ background: "rgba(255,200,0,0.45)", borderRadius: 2, padding: "0 1px" }}
    32→            >
    33→              {part.slice(1, -1)}
    34→            </mark>
    35→          );
    36→        }
    37→        return part;
    38→      })}
    39→    </code>
    40→  );
    41→}
    42→
    43→function Snippet({ raw, contentType }: { raw: string; contentType?: string }) {
    44→  if (contentType === "tool_use" || contentType === "tool_result") {
    45→    return <HighlightedCode raw={raw} />;
    46→  }
    47→  const terms: string[] = [];
    48→  const re = /«([^»]+)»/g;
    49→  let m: RegExpExecArray | null;
    50→  while ((m = re.exec(raw)) !== null) terms.push(m[1]);
    51→  const clean = raw.replace(/«([^»]*)»/g, "$1");
    52→  return <MarkdownView text={clean} highlightTerms={[...new Set(terms)]} />;
    53→}
