     5→
     6→interface TextBlock    { type: "text";        text: string }
     7→interface ToolUseBlock  { type: "tool_use";   id: string; name: string; input: unknown }
     8→export interface ToolResultBlock { type: "tool_result"; tool_use_id: string; content: unknown }
     9→type ContentBlock = TextBlock | ToolUseBlock | ToolResultBlock | { type: string; [k: string]: unknown };
    10→
    11→function blocks(content: unknown): ContentBlock[] { return Array.isArray(content) ? content as ContentBlock[] : []; }
    12→function str(v: unknown): string { return typeof v === "string" ? v : ""; }
    13→function fmt(iso: string | null): string {
    14→  if (!iso) return "";
    15→  const d = new Date(iso);
    16→  return String(d.getHours()).padStart(2, "0") + ":" + String(d.getMinutes()).padStart(2, "0") + ":" + String(d.getSeconds()).padStart(2, "0");
    17→}
    18→function truncate(v: unknown, max = 800): string {
    19→  const s = typeof v === "string" ? v : JSON.stringify(v, null, 2);
    20→  return s.length > max ? s.slice(0, max) + "\n…" : s;
    21→}
    22→
    23→function ToolUseRow({ block, result }: { block: ToolUseBlock; result?: ToolResultBlock }) {
    24→  const [expanded, setExpanded] = useState(false);
    25→  const inp = block.input as Record<string, unknown>;
    26→  const hint = (() => {
    27→    if (!inp) return "";
    28→    switch (block.name) {
    29→      case "Read": case "Write": case "Edit": return str(inp.file_path);
    30→      case "Bash":      return str(inp.command).replace(/\s+/g, " ").slice(0, 80);
    31→      case "Glob":      return str(inp.pattern);
    32→      case "Grep":      return str(inp.pattern);
    33→      case "WebFetch":  return str(inp.url);
    34→      case "WebSearch": return str(inp.query);
    35→      default: return "";
    36→    }
    37→  })();
    38→
    39→  return (
    40→    <Box onClick={() => setExpanded((v) => !v)} style={{ padding: "4px 0", borderBottom: "1px solid light-dark(var(--mantine-color-gray-1), var(--mantine-color-dark-5))", cursor: "pointer" }}>
    41→      <Group gap={6}>
    42→        <Text size="xs" c={result ? "green" : "blue"} fw={700} style={{ width: 14, textAlign: "center" }}>{result ? "✓" : "▶"}</Text>
    43→        <Text size="xs" fw={600} ff="monospace" style={{ flexShrink: 0 }}>{block.name}</Text>
    44→        {hint && <Text size="xs" c="dimmed" ff="monospace" style={{ flex: 1, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{hint}</Text>}
    45→        <Text size="xs" c="dimmed">{expanded ? "▲" : "▼"}</Text>
    46→      </Group>
    47→      <Collapse in={expanded}>
    48→        <Box mt={4} ml={20}>
    49→          <Text size="xs" c="dimmed" fw={700} tt="uppercase" mb={2}>input</Text>
    50→          <Code block style={{ fontSize: 11 }}>{truncate(block.input)}</Code>
    51→          {result && (
    52→            <>
    53→              <Text size="xs" c="dimmed" fw={700} tt="uppercase" mt={4} mb={2}>output</Text>
    54→              <Code block style={{ fontSize: 11 }}>{truncate(result.content)}</Code>
    55→            </>
    56→          )}
    57→        </Box>
    58→      </Collapse>
    59→    </Box>
    60→  );
    61→}
    62→
    63→function UserCard({ msg }: { msg: CheckpointMessage }) {
    64→  const d = msg.data as Record<string, unknown>;
    65→  const content = (d.message as Record<string, unknown> | undefined)?.content;
    66→  const text = typeof content === "string"
    67→    ? content
    68→    : blocks(content).filter((b): b is TextBlock => b.type === "text").map((b) => b.text).join("\n");
    69→  if (!text.trim()) return null;
    70→
    71→  const [expanded, setExpanded] = useState(false);
    72→  const preview = text.slice(0, 120).replace(/\n+/g, " ");
    73→  const hasMore = text.length > 120;
    74→
    75→  return (
    76→    <Box
    77→      onClick={hasMore ? () => setExpanded((v) => !v) : undefined}
    78→      style={{ borderLeft: "4px solid var(--mantine-color-indigo-5)", backgroundColor: "light-dark(var(--mantine-color-indigo-0), var(--mantine-color-dark-6))", padding: "8px 12px", cursor: hasMore ? "pointer" : "default" }}
    79→    >
    80→      <Group gap={8} mb={2}>
    81→        <Text size="xs" fw={700} c="indigo" tt="uppercase" style={{ letterSpacing: 0.5, flexShrink: 0 }}>→ User</Text>
    82→        <Text size="xs" fw={600} style={{ flex: 1, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{preview}</Text>
    83→        <Text size="xs" c="dimmed" style={{ flexShrink: 0 }}>{fmt(msg.timestamp)}</Text>
    84→        {hasMore && <Text size="xs" c="dimmed">{expanded ? "▲" : "▼"}</Text>}
    85→      </Group>
    86→      <Collapse in={expanded}>
    87→        <MarkdownView text={text} />
    88→      </Collapse>
    89→    </Box>
    90→  );
    91→}
    92→
    93→function AssistantCard({ msg, toolResults }: { msg: CheckpointMessage; toolResults: Map<string, ToolResultBlock> }) {
    94→  const d = msg.data as Record<string, unknown>;
    95→  const content = (d.message as Record<string, unknown> | undefined)?.content;
    96→  const allBlocks = blocks(content);
    97→  const textBlocks = allBlocks.filter((b): b is TextBlock => b.type === "text");
    98→  const toolUses   = allBlocks.filter((b): b is ToolUseBlock => b.type === "tool_use");
    99→  const fullText = textBlocks.map((b) => b.text).join("\n");
   100→  const preview = fullText.slice(0, 120).replace(/\n+/g, " ");
   101→  const hasMore = fullText.length > 120;
   102→  const [expanded, setExpanded] = useState(false);
   103→
   104→  return (
   105→    <Box style={{ borderLeft: "4px solid var(--mantine-color-orange-4)", backgroundColor: "light-dark(var(--mantine-color-white), var(--mantine-color-dark-7))", padding: "8px 12px" }}>
   106→      <Group
   107→        gap={8}
   108→        mb={2}
   109→        onClick={fullText ? () => setExpanded((v) => !v) : undefined}
   110→        style={{ cursor: fullText ? "pointer" : "default" }}
   111→      >
   112→        <Text size="xs" fw={700} c="orange" tt="uppercase" style={{ letterSpacing: 0.5, flexShrink: 0 }}>■ Assistant</Text>
   113→        {preview && <Text size="xs" fw={600} style={{ flex: 1, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{preview}</Text>}
   114→        <Text size="xs" c="dimmed" style={{ flexShrink: 0 }}>{fmt(msg.timestamp)}</Text>
   115→        {hasMore && <Text size="xs" c="dimmed">{expanded ? "▲" : "▼"}</Text>}
   116→      </Group>
   117→      <Collapse in={expanded}>
   118→        {fullText && <MarkdownView text={fullText} />}
   119→      </Collapse>
   120→      {toolUses.length > 0 && (
   121→        <Box mt={4} style={{ borderTop: "1px solid light-dark(var(--mantine-color-gray-1), var(--mantine-color-dark-5))" }}>
   122→          {toolUses.map((tu) => (
   123→            <ToolUseRow key={tu.id} block={tu} result={toolResults.get(tu.id)} />
   124→          ))}
   125→        </Box>
   126→      )}
   127→    </Box>
   128→  );
   129→}
   130→
   131→const COMPACT_COLOR = "light-dark(var(--mantine-color-gray-6), var(--mantine-color-gray-4))";
   132→const TYPE_STYLE: Record<string, { sym: string; color: string }> = {
   133→  progress: { sym: "◆", color: COMPACT_COLOR },
   134→  system:   { sym: "⚙", color: COMPACT_COLOR },
   135→  "file-history-snapshot": { sym: "📄", color: COMPACT_COLOR },
   136→};
   137→
   138→function CompactRow({ msg }: { msg: CheckpointMessage }) {
   139→  const style = TYPE_STYLE[msg.type] ?? { sym: "◆", color: COMPACT_COLOR };
   140→  const d = msg.data as Record<string, unknown>;
   141→  const hookEvent = str((d.data as Record<string, unknown> | undefined)?.hookEvent);
   142→  return (
   143→    <Group gap={6} px={12} py="3px" style={{ borderBottom: "1px solid light-dark(var(--mantine-color-gray-0), var(--mantine-color-dark-6))" }}>
   144→      <Text size="xs" style={{ color: style.color, width: 14, textAlign: "center" }}>{style.sym}</Text>
   145→      <Text size="xs" style={{ color: style.color, flex: 1 }}>{msg.type}{hookEvent ? ` · ${hookEvent}` : ""}</Text>
   146→      <Text size="xs" c="dimmed">{fmt(msg.timestamp)}</Text>
   147→    </Group>
   148→  );
   149→}
   150→
   151→interface Props {
   152→  msg: CheckpointMessage;
   153→  toolResults: Map<string, ToolResultBlock>;
   154→  showCompact: boolean;
   155→}
   156→
   157→export function CheckpointMessageItem({ msg, toolResults, showCompact }: Props) {
   158→  if (msg.type === "user") {
   159→    const d = msg.data as Record<string, unknown>;
   160→    const content = (d.message as Record<string, unknown> | undefined)?.content;
   161→    if (Array.isArray(content) && content.every((b: ContentBlock) => b.type === "tool_result")) return null;
   162→    return <UserCard msg={msg} />;
   163→  }
   164→  if (msg.type === "assistant") return <AssistantCard msg={msg} toolResults={toolResults} />;
   165→  if (!showCompact) return null;
   166→  return <CompactRow msg={msg} />;
   167→}
