    18→  const parts = text.split(new RegExp(`(${pattern})`, "gi"));
    19→  return parts.map((p, i) =>
    20→    i % 2 === 1
    21→      ? <mark key={i} style={{ background: "rgba(255,200,0,0.45)", borderRadius: 2, padding: "0 1px" }}>{p}</mark>
    22→      : p
    23→  );
    24→}
