      lastAssistantThinking = null;
      lastAssistantLogEventId = null;
      lastThinkingLogEventId = null;
      lastThinkingUuid = null;
      lastToolsLogEventId = null;
      lastToolsUuid = null;
      currentTurnLogEventIds.length = 0;
    }
