            ) : (
              <Box
                className="d2h-wrapper"
                style={{ fontSize: 12, overflowX: "auto" }}
                dangerouslySetInnerHTML={{
                  __html: diff2htmlHtml(diffPatch, {
                    drawFileList: true,
                    matching: "lines",
                    outputFormat: "line-by-line",
                    colorScheme: "light",
