    12→  const [loading, setLoading]       = useState(true);
    13→  const [error, setError]           = useState<string | null>(null);
    14→  const [deleteTarget, setDeleteTarget] = useState<RepoConfig | null>(null);
    15→
    16→  const [modalOpen, { open: openModal, close: closeModal }] = useDisclosure(false);
    17→  const [form, setForm] = useState({ name: "", remote: "", localPath: "" });
    18→  const [formError, setFormError]   = useState<string | null>(null);
    19→  const [submitting, setSubmitting] = useState(false);
    20→
    21→  const load = async () => {
    22→    try {
    23→      const [r, c] = await Promise.all([fetchRepos(), fetchCurrentRepo()]);
    24→      setRepos(r);
    25→      setCurrent(c);
    26→      setError(null);
    27→    } catch (e) {
    28→      setError(String(e));
    29→    } finally {
    30→      setLoading(false);
    31→    }
    32→  };
    33→
    34→  useEffect(() => { void load(); }, []);
    35→
    36→  const handleAdd = async () => {
    37→    if (!form.name.trim() || !form.localPath.trim()) {
    38→      setFormError("Name and local path are required.");
    39→      return;
    40→    }
    41→    setSubmitting(true);
    42→    setFormError(null);
    43→    try {
    44→      await addRepo({ name: form.name.trim(), remote: form.remote.trim(), localPath: form.localPath.trim() });
    45→      setForm({ name: "", remote: "", localPath: "" });
    46→      closeModal();
    47→      await load();
    48→    } catch (e) {
    49→      setFormError(String(e));
    50→    } finally {
    51→      setSubmitting(false);
    52→    }
    53→  };
    54→
    55→  const handleDelete = async (repo: RepoConfig) => {
    56→    try {
    57→      await deleteRepo(repo.localPath);
    58→      setDeleteTarget(null);
    59→      await load();
    60→    } catch (e) {
    61→      setError(String(e));
    62→    }
    63→  };
    64→
    65→  if (loading) {
    66→    return <Center h={200}><Loader size="sm" /></Center>;
    67→  }
    68→
    69→  return (
    70→    <Box p="md" style={{ maxWidth: 800 }}>
    71→      <Group justify="space-between" mb="md">
    72→        <Text fw={600} size="lg">Repositories</Text>
    73→        <Button size="xs" onClick={openModal}>Add repo</Button>
    74→      </Group>
    75→
    76→      {error && (
    77→        <Alert color="red" mb="md">{error}</Alert>
    78→      )}
    79→
    80→      {repos.length === 0 ? (
    81→        <Text c="dimmed" size="sm">No repositories configured. Add one to get started.</Text>
    82→      ) : (
    83→        <Table striped withTableBorder>
    84→          <Table.Thead>
    85→            <Table.Tr>
    86→              <Table.Th>Name</Table.Th>
    87→              <Table.Th>Local path</Table.Th>
    88→              <Table.Th>Remote</Table.Th>
    89→              <Table.Th />
    90→            </Table.Tr>
    91→          </Table.Thead>
    92→          <Table.Tbody>
    93→            {repos.map((repo) => {
    94→              const isCurrent = current?.localPath === repo.localPath;
    95→              return (
    96→                <Table.Tr key={repo.localPath}>
    97→                  <Table.Td>
    98→                    <Group gap={6}>
    99→                      <Text size="sm" fw={500}>{repo.name}</Text>
   100→                      {isCurrent && <Badge size="xs" color="indigo">current</Badge>}
   101→                    </Group>
   102→                  </Table.Td>
   103→                  <Table.Td>
   104→                    <Text size="sm" c="dimmed" ff="monospace">{repo.localPath}</Text>
   105→                  </Table.Td>
   106→                  <Table.Td>
   107→                    <Text size="sm" c="dimmed" ff="monospace">{repo.remote || "—"}</Text>
   108→                  </Table.Td>
   109→                  <Table.Td>
   110→                    <ActionIcon
   111→                      variant="subtle"
   112→                      color="red"
   113→                      size="sm"
   114→                      disabled={isCurrent}
   115→                      title={isCurrent ? "Cannot remove the active repo" : "Remove"}
   116→                      onClick={() => setDeleteTarget(repo)}
   117→                    >
   118→                      ✕
   119→                    </ActionIcon>
   120→                  </Table.Td>
   121→                </Table.Tr>
   122→              );
   123→            })}
   124→          </Table.Tbody>
   125→        </Table>
   126→      )}
   127→
   128→      {/* Add repo modal */}
   129→      <Modal opened={modalOpen} onClose={closeModal} title="Add repository" size="sm">
   130→        <Stack gap="sm">
   131→          <TextInput
   132→            label="Name"
   133→            placeholder="my-project"
   134→            value={form.name}
   135→            onChange={(e) => { const v = e.currentTarget.value; setForm((f) => ({ ...f, name: v })); }}
   136→            required
   137→          />
   138→          <TextInput
   139→            label="Local path"
   140→            placeholder="/Users/you/projects/my-project"
   141→            value={form.localPath}
   142→            onChange={(e) => { const v = e.currentTarget.value; setForm((f) => ({ ...f, localPath: v })); }}
   143→            required
   144→          />
   145→          <TextInput
   146→            label="Remote URL"
   147→            placeholder="git@github.com:you/my-project.git"
   148→            value={form.remote}
   149→            onChange={(e) => { const v = e.currentTarget.value; setForm((f) => ({ ...f, remote: v })); }}
   150→          />
   151→          {formError && <Alert color="red" size="xs">{formError}</Alert>}
   152→          <Divider />
   153→          <Group justify="flex-end">
   154→            <Button variant="subtle" size="xs" onClick={closeModal} disabled={submitting}>Cancel</Button>
   155→            <Button size="xs" onClick={handleAdd} loading={submitting}>Add</Button>
   156→          </Group>
   157→        </Stack>
   158→      </Modal>
   159→
   160→      {/* Delete confirmation modal */}
   161→      <Modal
   162→        opened={deleteTarget !== null}
   163→        onClose={() => setDeleteTarget(null)}
   164→        title="Remove repository"
   165→        size="sm"
   166→      >
   167→        <Stack gap="sm">
   168→          <Text size="sm">
   169→            Remove <Text span fw={600}>{deleteTarget?.name}</Text> from Gossamer?
   170→            This only removes it from the config — the local files and database are not deleted.
   171→          </Text>
   172→          <Group justify="flex-end">
   173→            <Button variant="subtle" size="xs" onClick={() => setDeleteTarget(null)}>Cancel</Button>
   174→            <Button size="xs" color="red" onClick={() => deleteTarget && handleDelete(deleteTarget)}>
   175→              Remove
   176→            </Button>
   177→          </Group>
   178→        </Stack>
   179→      </Modal>
   180→    </Box>
   181→  );
   182→}
