   366→export function subscribeToUpdates(onUpdate: () => void): () => void {
   367→  let ws: WebSocket | null = null;
   368→  let timer: ReturnType<typeof setTimeout> | null = null;
   369→  let closed = false;
   370→  let delay = 1000;
   371→
   372→  function connect() {
   373→    if (closed) return;
   374→    ws = new WebSocket(WS_URL);
   375→
   376→    ws.onopen = () => {
   377→      delay = 1000; // reset backoff on successful connection
   378→    };
   379→
   380→    ws.onmessage = (e) => {
   381→      try {
   382→        const msg = JSON.parse(e.data as string) as { type: string };
   383→        if (msg.type === "sessions_updated") onUpdate();
   384→      } catch {
   385→        // ignore malformed messages
   386→      }
   387→    };
   388→
   389→    ws.onclose = () => {
   390→      if (closed) return;
   391→      timer = setTimeout(() => {
   392→        delay = Math.min(delay * 2, 30000);
   393→        connect();
   394→      }, delay);
   395→    };
   396→
   397→    ws.onerror = () => {
   398→      ws?.close();
   399→    };
   400→  }
   401→
   402→  connect();
   403→
   404→  return () => {
   405→    closed = true;
   406→    if (timer !== null) clearTimeout(timer);
   407→    ws?.close();
   408→  };
   409→}
