   101→export function BranchLog() {
   102→  const [searchParams] = useSearchParams();
   103→  const localPath = searchParams.get("localPath") ?? "";
   104→  const branch    = searchParams.get("branch")    ?? "";
   105→  const repoName  = searchParams.get("repoName")  ?? null;
   106→
   107→  const [items, setItems]             = useState<BranchLogEntry[]>([]);
   108→  const [page, setPage]               = useState(0);
   109→  const [hasMore, setHasMore]         = useState(false);
   110→  const [loading, setLoading]         = useState(true);
   111→  const [loadingMore, setLoadingMore] = useState(false);
   112→  const [error, setError]             = useState<string | null>(null);
   113→  const { setCrumbs } = useBreadcrumb();
   114→
   115→  useEffect(() => {
   116→    setCrumbs([
   117→      ...(repoName ? [{ label: repoName }] : []),
   118→      { label: branch },
   119→    ]);
   120→    setLoading(true);
   121→    setItems([]);
   122→    setPage(0);
   123→    fetchBranchLog(localPath, branch, 0)
   124→      .then(({ entries, hasMore: more }) => {
   125→        setItems(entries);
   126→        setHasMore(more);
   127→      })
   128→      .catch((e: unknown) => setError(String(e)))
   129→      .finally(() => setLoading(false));
   130→  }, [localPath, branch]);
   131→
   132→  const loadMore = () => {
   133→    const nextPage = page + 1;
   134→    setLoadingMore(true);
   135→    fetchBranchLog(localPath, branch, nextPage)
   136→      .then(({ entries, hasMore: more }) => {
   137→        setItems((prev) => [...prev, ...entries]);
   138→        setPage(nextPage);
   139→        setHasMore(more);
   140→      })
   141→      .catch((e: unknown) => setError(String(e)))
   142→      .finally(() => setLoadingMore(false));
   143→  };
   144→
   145→  if (loading) return <Center style={{ flex: 1 }}><Loader size="md" color="teal" /></Center>;
   146→  if (error)   return <Center style={{ flex: 1 }}><Text c="red">{error}</Text></Center>;
   147→
   148→  if (items.length === 0) {
   149→    return (
   150→      <Center style={{ flex: 1 }}>
   151→        <Text c="dimmed" size="sm">No checkpoints found on branch <Text span ff="monospace">{branch}</Text>.</Text>
   152→      </Center>
   153→    );
   154→  }
   155→
   156→  return (
   157→    <ScrollArea style={{ flex: 1 }}>
   158→      <Box style={{ maxWidth: 860, margin: "0 auto", paddingBottom: 40 }}>
   159→        {items.map((entry) => {
   160→          const name = entry.gitUserName ?? entry.gitUserEmail ?? null;
   161→          const userInfo: UserInfo | undefined = name
   162→            ? { name, avatarUrl: entry.gitUserName ? `https://github.com/${entry.gitUserName}.png?size=40` : undefined }
   163→            : undefined;
   164→          return (
   165→            <EntryDetail
   166→              key={`${entry.checkpointId}-${entry.sessionId}`}
   167→              entry={entry}
   168→              localPath={localPath}
   169→              userInfo={userInfo}
   170→            />
   171→          );
   172→        })}
   173→        {hasMore && (
   174→          <Center py="xl">
   175→            <Button variant="subtle" color="teal" loading={loadingMore} onClick={loadMore}>
   176→              Load more
   177→            </Button>
   178→          </Center>
   179→        )}
   180→      </Box>
   181→    </ScrollArea>
   182→  );
   183→}
