    32→function gitConfigGet(key: string, cwd?: string): string | null {
    33→  try {
    34→    return execSync(`git config ${key}`, {
    35→      cwd,
    36→      encoding: "utf8",
    37→      stdio: ["ignore", "pipe", "ignore"],
