    79→// ─── Mapping helpers ──────────────────────────────────────────────────────────
    80→
    81→// SQLite has a limit of 999 bind variables per statement. When doing IN queries
    82→// over large sets, chunk and union the results.
    83→const SQLITE_IN_CHUNK = 500;
    84→
    85→async function findManyInChunks<T>(
    86→  ids: string[],
    87→  fetch: (chunk: string[]) => Promise<T[]>,
    88→): Promise<T[]> {
    89→  if (ids.length === 0) return [];
    90→  const results: T[] = [];
    91→  for (let i = 0; i < ids.length; i += SQLITE_IN_CHUNK) {
    92→    const chunk = ids.slice(i, i + SQLITE_IN_CHUNK);
    93→    results.push(...await fetch(chunk));
    94→  }
    95→  return results;
    96→}
