   100→export async function startServer(dbPath: string, port: number, repoDir?: string): Promise<void> {
   101→  // Strip CLAUDECODE so spawned sessions are not blocked by nested-session detection
   102→  delete process.env.CLAUDECODE;
   103→
   104→  const db = await getDb(dbPath);
   105→
   106→  // Ensure FTS table exists and is up-to-date on startup
   107→  await setupLogContentFts(db);
   108→  await syncLogContentFts(db);
   109→
   110→  const app = express();
   111→  app.use(cors());
   112→  app.use(express.json());
   113→
   114→  // Resolve git user and repo name from repo config once at startup
   115→  const gitUser  = getGitUser(repoDir);
   116→  const repoName = repoDir ? basename(repoDir) : null;
   117→
   118→  // GET /api/sessions — reconstructed from CheckpointSessionMetadata + ShadowSession
   119→  app.get("/api/sessions", async (_req, res) => {
   120→    try {
   121→      // Latest checkpoint meta per sessionId (asc order so map always ends on latest)
   122→      const allMetas = await db.checkpointSessionMetadata.findMany({
   123→        select: {
   124→          sessionId: true,
   125→          checkpointId: true,
   126→          branch: true,
   127→          summary: { select: { intent: true } },
   128→        },
   129→        orderBy: { createdAt: "asc" },
   130→      });
   131→      const cpMap = new Map<string, { branch: string | null; intent: string | null; checkpointId: string }>();
   132→      for (const m of allMetas) {
   133→        cpMap.set(m.sessionId, { branch: m.branch, intent: m.summary?.intent ?? null, checkpointId: m.checkpointId });
   134→      }
   135→
   136→      // Git user per checkpoint (from commit author stored at index time)
   137→      const allCheckpointIds = [...new Set(allMetas.map((m) => m.checkpointId))];
   138→      const cpUserRows = allCheckpointIds.length > 0
   139→        ? await db.checkpointMetadata.findMany({
   140→            where: { checkpointId: { in: allCheckpointIds } },
   141→            select: { checkpointId: true, gitUserName: true, gitUserEmail: true },
   142→          })
   143→        : [];
   144→      const cpUserMap = new Map(cpUserRows.map((r) => [r.checkpointId, r]));
   145→
   146→      const shadows = await db.shadowSession.findMany();
   147→      const shadowMap = new Map(shadows.map((s) => [s.sessionId, s]));
   148→
   149→      const allIds = [...new Set([...cpMap.keys(), ...shadows.map((s) => s.sessionId)])];
   150→      if (allIds.length === 0) {
   151→        res.json([]);
   152→        return;
   153→      }
   154→
   155→      // Min/max LogEvent timestamps per session
   156→      const times = await db.logEvent.groupBy({
   157→        by: ["sessionId"],
   158→        where: { sessionId: { in: allIds }, timestamp: { not: null } },
   159→        _min: { timestamp: true },
   160→        _max: { timestamp: true },
   161→      });
   162→      const timeMap = new Map(
   163→        times.map((r) => [r.sessionId!, { startedAt: r._min.timestamp, updatedAt: r._max.timestamp }])
   164→      );
   165→
   166→      // First cwd per session
   167→      const cwdRows = await db.logEvent.findMany({
   168→        where: { sessionId: { in: allIds }, cwd: { not: null } },
   169→        distinct: ["sessionId"],
   170→        orderBy: { id: "asc" },
   171→        select: { sessionId: true, cwd: true },
   172→      });
   173→      const cwdMap = new Map(cwdRows.map((e) => [e.sessionId!, e.cwd]));
   174→
   175→      const result: SessionResponse[] = allIds.map((sessionId) => {
   176→        const cp     = cpMap.get(sessionId) ?? null;
   177→        const shadow = shadowMap.get(sessionId) ?? null;
   178→        const t      = timeMap.get(sessionId);
   179→        const startedAt = t?.startedAt ?? shadow?.createdAt ?? null;
   180→        const updatedAt = t?.updatedAt ?? shadow?.createdAt ?? null;
   181→        const cpUser = cp ? cpUserMap.get(cp.checkpointId) ?? null : null;
   182→        return {
   183→          sessionId,
   184→          startedAt: startedAt?.toISOString() ?? new Date(0).toISOString(),
   185→          updatedAt: updatedAt?.toISOString() ?? new Date(0).toISOString(),
   186→          cwd:             cwdMap.get(sessionId) ?? shadow?.cwd ?? "",
   187→          repoRoot:        repoDir ?? null,
   188→          repoName:        repoName,
   189→          parentSessionId: null,
   190→          childSessionIds: [],
   191→          gitUserName:     cpUser?.gitUserName ?? gitUser.name,
   192→          gitUserEmail:    cpUser?.gitUserEmail ?? gitUser.email,
   193→          prompt:          shadow?.prompt ?? null,
   194→          summary:         null,
