   584→  // GET /api/branch-log?localPath=<>&branch=<>
   585→  // Walks git log on the branch, parses "Entire-Checkpoint: <id>" trailers from
   586→  // commit bodies, then looks up each checkpoint in the DB individually.
   587→  app.get("/api/branch-log", async (req, res) => {
   588→    try {
   589→      const localPath = typeof req.query.localPath === "string" ? req.query.localPath : null;
   590→      const branch    = typeof req.query.branch    === "string" ? req.query.branch    : null;
   591→      if (!localPath || !branch) {
   592→        res.status(400).json({ error: "localPath and branch are required" });
   593→        return;
   594→      }
   595→
   596→      const page = typeof req.query.page === "string" ? Math.max(0, parseInt(req.query.page, 10) || 0) : 0;
   597→      const PAGE_SIZE = 50;
   598→
   599→      const repo = findRepo(localPath);
   600→      if (!repo) { res.status(404).json({ error: "Repo not found in config" }); return; }
   601→
   602→      const repoDb = repo.dbPath === dbPath ? db : await getDb(repo.dbPath);
   603→
   604→      // Walk git log and collect checkpoint IDs in commit order
   605→      const orderedIds: string[] = [];
   606→      const seenIds = new Set<string>();
   607→      try {
   608→        const { stdout: gitOut } = await exec(
   609→          `git -C ${JSON.stringify(localPath)} log --format=%B%x1e --max-count=${PAGE_SIZE} --skip=${page * PAGE_SIZE} ${JSON.stringify(branch)}`,
   610→          { timeout: 10_000 },
   611→        );
   612→        for (const body of gitOut.split("\x1e")) {
   613→          const match = body.match(/^Entire-Checkpoint:\s*(\S+)$/m);
   614→          if (match && !seenIds.has(match[1])) {
   615→            seenIds.add(match[1]);
   616→            orderedIds.push(match[1]);
   617→          }
   618→        }
   619→      } catch { /* git unavailable or branch not found */ }
   620→
   621→      const result = [];
   622→      for (const checkpointId of orderedIds) {
   623→        const [sessions, cpMeta] = await Promise.all([
   624→          repoDb.checkpointSessionMetadata.findMany({
   625→            where:   { checkpointId },
   626→            orderBy: { createdAt: "asc" },
   627→            include: { ...V2_SESSION_INCLUDE, tokenUsage: true, filesTouched: { include: { filePath: true } } },
   628→          }),
   629→          repoDb.checkpointMetadata.findUnique({
   630→            where:  { checkpointId },
   631→            select: { gitUserName: true, gitUserEmail: true },
   632→          }),
   633→        ]);
   634→        for (const s of sessions) {
   635→          result.push({
   636→            checkpointId:  s.checkpointId,
   637→            sessionId:     s.sessionId,
   638→            branch:        s.branch,
   639→            createdAt:     s.createdAt?.toISOString() ?? null,
   640→            gitUserName:   cpMeta?.gitUserName  ?? null,
   641→            gitUserEmail:  cpMeta?.gitUserEmail ?? null,
   642→            filesTouched:  s.filesTouched.map((f) => f.filePath.path),
   643→            tokenUsage:   s.tokenUsage ? {
   644→              inputTokens:         s.tokenUsage.inputTokens,
   645→              cacheCreationTokens: s.tokenUsage.cacheCreationTokens,
   646→              cacheReadTokens:     s.tokenUsage.cacheReadTokens,
   647→              outputTokens:        s.tokenUsage.outputTokens,
   648→              apiCallCount:        s.tokenUsage.apiCallCount,
   649→            } : null,
   650→            summary:   s.summary ? mapV2Summary(s.summary) : null,
   651→          });
   652→        }
   653→      }
   654→
   655→      res.json({ entries: result, hasMore: orderedIds.length === PAGE_SIZE });
   656→    } catch (err) {
   657→      res.status(500).json({ error: String(err) });
   658→    }
   659→  });
