          <SectionBlock title="Files changed">
            {diffPatch === null ? (
              <Text size="xs" c="dimmed">Loading…</Text>
            ) : diffPatch === "" ? (
              fileCount > 0 ? (
                <Box style={{ display: "flex", flexDirection: "column", gap: 3 }}>
