      const safeId = sessionId.replace(/'/g, "");
      const script = [
        `tell application "Terminal"`,
        `  activate`,
        `  do script "cd '${safeCwd}' && claude resume ${safeId}"`,
        `end tell`,
      ].join("\n");
      execSync(`osascript -e '${script.replace(/'/g, "'\\''")}'`);
