              </Group>
              {cp.createdAt && (
                <Text size="xs" c="dimmed" mt={2}><TimeAgo iso={cp.createdAt} /></Text>
              )}
            </UnstyledButton>
          );
        })}
      </Box>

      {/* ── Right: chat panel (2/3) ───────────────────────────────────── */}
      <ScrollArea style={{ flex: 1 }} viewportRef={viewportRef}>
