    28→export type DisplayItem =
    29→  | { kind: "event"; event: Event }
    30→  | { kind: "toolGroup"; tools: ToolUseData[] }
    31→  | { kind: "checkpoint"; checkpoint: SessionCheckpoint };
    32→
    33→export type RenderItem =
    34→  | { kind: "event"; event: Event }
