   184→                {toolGroups.map((tools, i) => (
   185→                  <ToolGroupItem key={i} tools={tools} autoExpand={expandTools} matchTerms={matchTerms} targetLogEventId={expandTools ? targetLogEventId : null} />
   186→                ))}
   187→              </Box>
   188→            </Collapse>
   189→          </Box>
   190→        )}
   191→      </Box>
   192→    </Box>
   193→  );
