   196→// TODO: we're dropping the UUIDs from LogEventItems, or at least mixing them up into currentTurnLogEventIds.
   197→// We need to attach these UUIDs to the components that these generate. That way the scrolling will work.
   198→/**
   199→ * Convert LogEventItems (from full.jsonl tables) into pseudo-Event objects that
   200→ * match the shape the existing UI components expect.  This lets all downstream
   201→ * grouping and rendering code remain unchanged.
   202→ */
   203→export function logEventsToEvents(logEvents: LogEventItem[]): Event[] {
   204→  const result: Event[] = [];
   205→  let id = -1;
   206→  let lastAssistantText: string | null = null;
   207→  let lastAssistantThinking: string | null = null;
   208→  let lastAssistantLogEventId: number | null = null;
   209→  let lastThinkingLogEventId: number | null = null;
   210→  let lastThinkingUuid: string | null = null;
   211→  let lastToolsLogEventId: number | null = null;
   212→  let lastToolsUuid: string | null = null;
   213→  let hasRedactedThinking = false;
   214→  // All LogEvent IDs seen in the current assistant turn (thinking, text, tool_use may be separate events)
   215→  const currentTurnLogEventIds: number[] = [];
   216→
   217→  // TODO: look at which event types are useful.
   218→  const filtered = logEvents.filter(
   219→    (e) => !e.isSidechain && e.type !== "file-history-snapshot" && e.type !== "progress",
   220→  );
   221→
   222→  // Virtual SessionStart divider
   223→  const first = filtered[0];
   224→  if (first) {
   225→    result.push({ id: id--, timestamp: first.timestamp ?? "", event: "SessionStart", sessionId: first.sessionId ?? "", blocked: false, data: { cwd: first.cwd ?? "" }, summary: null, keywords: [], _sourceLogEventId: first.id });
   226→  }
   227→
   228→  for (const le of filtered) {
   229→    const ts  = le.timestamp ?? "";
   230→    const sid = le.sessionId ?? "";
   231→
   232→    if (le.type === "user") {
   233→      const toolResults = le.contents.filter((c) => c.contentType === "tool_result");
   234→      // TODO: show images and other content types
   235→      const textBlocks  = le.contents.filter((c) => c.contentType === "text");
   236→
   237→      if (toolResults.length > 0) {
   238→        for (const tr of toolResults) {
   239→          const failed = tr.isError === true;
   240→          result.push({
   241→            id: id--,
   242→            timestamp: ts,
   243→            event: failed ? "PostToolUseFailure" : "PostToolUse",
   244→            sessionId: sid,
   245→            blocked: false,
   246→            data: {
   247→              tool_use_id:   tr.toolUseId,
   248→              tool_response: !failed ? (tr.toolResultContent ?? "") : undefined,
   249→              error:          failed ? (tr.toolResultContent ?? "") : undefined,
   250→            },
   251→            summary: null, keywords: [], _sourceLogEventId: le.id, _sourceUuid: le.uuid ?? undefined,
   252→          });
   253→        }
   254→      } else if (textBlocks.length > 0) {
   255→        const prompt = textBlocks.map((b) => b.text ?? "").join("\n\n");
   256→        result.push({ id: id--, timestamp: ts, event: "UserPromptSubmit", sessionId: sid, blocked: false, data: { prompt }, summary: null, keywords: [], _sourceLogEventId: le.id, _sourceUuid: le.uuid ?? undefined });
   257→      }
   258→
   259→    } else if (le.type === "assistant") {
   260→      const toolUses      = le.contents.filter((c) => c.contentType === "tool_use");
   261→      const textBlocks    = le.contents.filter((c) => c.contentType === "text");
   262→      const thinkingBlocks = le.contents.filter((c) => c.contentType === "thinking");
   263→      const redactedThinkingBlocks = le.contents.filter((c) => c.contentType === "redacted_thinking");
   264→
   265→      // Track all LogEvent IDs in this turn so thinking-only events are reachable
   266→      if (!currentTurnLogEventIds.includes(le.id)) currentTurnLogEventIds.push(le.id);
   267→
   268→      if (textBlocks.length > 0) {
   269→        const newText = textBlocks.map((b) => b.text ?? "").filter(Boolean).join("\n\n");
   270→        // If there was already planning text and tool uses have been emitted since,
   271→        // fold the planning text into the thinking block so it isn't lost.
   272→        if (lastAssistantText !== null && lastToolsLogEventId !== null) {
   273→          lastAssistantThinking = lastAssistantThinking
   274→            ? lastAssistantThinking + "\n\n" + lastAssistantText
   275→            : lastAssistantText;
   276→        }
   277→        lastAssistantText = newText;
   278→        lastAssistantLogEventId = le.id;
   279→      }
   280→      if (thinkingBlocks.length > 0) {
   281→        const thinking = thinkingBlocks.map((b) => b.thinking ?? "").filter(Boolean).join("\n\n");
   282→        lastAssistantThinking = lastAssistantThinking ? lastAssistantThinking + "\n\n" + thinking : thinking;
   283→        lastThinkingLogEventId = le.id;
   284→        lastThinkingUuid = le.uuid ?? null;
   285→        if (lastAssistantLogEventId === null) lastAssistantLogEventId = le.id;
   286→      }
   287→      if (redactedThinkingBlocks.length > 0) {
   288→        hasRedactedThinking = true;
   289→        if (lastAssistantLogEventId === null) lastAssistantLogEventId = le.id;
   290→      }
   291→
   292→      for (const tu of toolUses) {
   293→        lastToolsLogEventId = le.id;
   294→        lastToolsUuid = le.uuid ?? null;
   295→        result.push({
   296→          id: id--,
   297→          timestamp: ts,
   298→          event: "PreToolUse",
   299→          sessionId: sid,
   300→          blocked: false,
   301→          data: { tool_name: tu.toolName ?? "?", tool_use_id: tu.toolUseId, tool_input: tu.toolInput },
   302→          summary: null, keywords: [], _sourceLogEventId: le.id, _sourceUuid: le.uuid ?? undefined,
   303→        });
   304→      }
   305→
   306→    } else if (le.type === "system" && le.systemData?.subtype === "stop_hook_summary") {
   307→      const primaryId = lastAssistantLogEventId ?? le.id;
   308→      const extraIds = currentTurnLogEventIds.filter((x) => x !== primaryId);
   309→      result.push({
   310→        id: id--,
   311→        timestamp: ts,
   312→        event: "Stop",
   313→        sessionId: sid,
   314→        blocked: le.systemData.preventedContinuation ?? false,
   315→        data: {
   316→          last_assistant_message: lastAssistantText ?? "",
   317→          thinking: lastAssistantThinking ?? "",
   318→          reason: le.systemData.stopReason ?? "",
   319→          thinkingLogEventId: lastThinkingLogEventId ?? undefined,
   320→          thinkingUuid: lastThinkingUuid ?? undefined,
   321→          toolsLogEventId: lastToolsLogEventId ?? undefined,
   322→          toolsUuid: lastToolsUuid ?? undefined,
   323→          hasRedactedThinking,
   324→        },
   325→        summary: null, keywords: [],
   326→        _sourceLogEventId: primaryId,
   327→        _extraSourceLogEventIds: extraIds.length > 0 ? extraIds : undefined,
   328→      });
   329→      lastAssistantText = null;
   330→      lastAssistantThinking = null;
   331→      lastAssistantLogEventId = null;
   332→      lastThinkingLogEventId = null;
   333→      lastThinkingUuid = null;
   334→      lastToolsLogEventId = null;
   335→      lastToolsUuid = null;
   336→      hasRedactedThinking = false;
   337→      currentTurnLogEventIds.length = 0;
   338→    }
   339→  }
   340→
   341→  // Flush any trailing assistant text that had no stop event
   342→  if (lastAssistantText !== null && filtered.length > 0) {
   343→    const last = filtered[filtered.length - 1];
   344→    const primaryId = lastAssistantLogEventId ?? last.id;
   345→    const extraIds = currentTurnLogEventIds.filter((x) => x !== primaryId);
   346→    result.push({
   347→      id: id--,
   348→      timestamp: last.timestamp ?? "",
   349→      event: "Stop",
   350→      sessionId: last.sessionId ?? "",
   351→      blocked: false,
   352→      data: { last_assistant_message: lastAssistantText, thinking: lastAssistantThinking ?? "", reason: "" },
   353→      summary: null, keywords: [],
   354→      _sourceLogEventId: primaryId,
   355→      _extraSourceLogEventIds: extraIds.length > 0 ? extraIds : undefined,
   356→    });
   357→  }
   358→
   359→  return result;
   360→}
