   570→// ── Search snippet helpers ─────────────────────────────────────────────────────
   571→
   572→function extractMatchTerms(snippet: string): string[] {
   573→  const terms: string[] = [];
   574→  const re = /«([^»]+)»/g;
   575→  let m: RegExpExecArray | null;
   576→  while ((m = re.exec(snippet)) !== null) terms.push(m[1]);
   577→  return [...new Set(terms)];
   578→}
   579→
   580→// ── Source log event ID extractor ─────────────────────────────────────────────
   581→
   582→function getItemSourceIds(item: RenderItem): number[] {
   583→  if (item.kind === "event") {
   584→    const ids = item.event._sourceLogEventId != null ? [item.event._sourceLogEventId] : [];
   585→    if (item.event._extraSourceLogEventIds) ids.push(...item.event._extraSourceLogEventIds);
   586→    return ids;
   587→  }
   588→  if (item.kind === "claudeTurn") {
   589→    const ids: number[] = [];
   590→    for (const group of item.toolGroups) {
   591→      for (const tool of group) {
   592→        if (tool.pre._sourceLogEventId != null) ids.push(tool.pre._sourceLogEventId);
   593→        if (tool.pre._extraSourceLogEventIds) ids.push(...tool.pre._extraSourceLogEventIds);
   594→        if (tool.post?._sourceLogEventId != null) ids.push(tool.post._sourceLogEventId);
   595→        if (tool.post?._extraSourceLogEventIds) ids.push(...tool.post._extraSourceLogEventIds);
   596→      }
   597→    }
   598→    if (item.stop?._sourceLogEventId != null) ids.push(item.stop._sourceLogEventId);
   599→    if (item.stop?._extraSourceLogEventIds) ids.push(...item.stop._extraSourceLogEventIds);
   600→    return ids;
   601→  }
   602→  return [];
   603→}
   604→
   605→function buildCheckpointGroups(
   606→  logEvs: LogEventItem[],
   607→  checkpoints: SessionCheckpoint[],
   608→): Map<string, RenderItem[]> {
   609→  const sorted = [...checkpoints].sort((a, b) => (a.createdAt ?? "") < (b.createdAt ?? "") ? -1 : 1);
   610→  const buckets = new Map<string, LogEventItem[]>();
   611→  for (const cp of sorted) buckets.set(cp.checkpointId, []);
   612→  buckets.set("shadow", []);
   613→
   614→  for (const ev of logEvs) {
   615→    const evTime = ev.timestamp ?? "";
   616→    let placed = false;
   617→    for (const cp of sorted) {
   618→      if (evTime <= (cp.createdAt ?? "")) {
   619→        buckets.get(cp.checkpointId)!.push(ev);
   620→        placed = true;
   621→        break;
   622→      }
   623→    }
   624→    if (!placed) buckets.get("shadow")!.push(ev);
   625→  }
   626→
   627→  const result = new Map<string, RenderItem[]>();
   628→  for (const [key, evs] of buckets) {
   629→    result.set(key, groupClaudeTurns(groupEvents(logEventsToEvents(evs))));
   630→  }
   631→  return result;
   632→}
   633→
   634→function findGroupForLogEvent(groups: Map<string, RenderItem[]>, logEventId: number): string | null {
   635→  for (const [key, items] of groups) {
   636→    for (const item of items) {
   637→      if (getItemSourceIds(item).includes(logEventId)) return key;
   638→    }
   639→  }
   640→  return null;
   641→}
