          )}
          <Text size="xs" fw={600} c={session?.isLive ? "teal" : "dimmed"}>
            {session?.isLive ? "In progress" : "Uncommitted changes"}
          </Text>
        </Group>
        {session?.prompt && (
          <Text size="xs" c="dimmed" lineClamp={2}>{session.prompt}</Text>
