      </UnstyledButton>

      {/* Real checkpoints, newest-first */}
      {sidebarCheckpoints.map((cp) => {
        const label = cp.summary?.intent ?? cp.commitMessage ?? null;
        const isSelected = selectedId === cp.checkpointId;
